#include<bits/stdc++.h>
using namespace std;
int a[100005],f[100005]={0},f2[100005]={0};
int main(void){
	int n=0,size=0,len=0;
	for(int i=1;cin>>a[i];i++)n++;
	for(int i=1;i<=n;i++){
		if(f[size]<a[i])f[++size]=a[i];
		else{
			int l=1,r=size;
			while(l<=r){
				int mid=(l+r)/2;
				if(f[mid]<a[i])l=mid+1;
				else r=mid-1; 
			}
			f[l]=a[i];
		}
	}
	for(int i=1;i<=n;i++){
		cin>>a[i];
		if(f2[len]>=a[i])f2[++len]=a[i];
		else{
			int l=0,r=len;
			while(l<=r){
				int mid=(l+r)/2;
				if(f2[mid]>=a[i])l=mid+1;
				else r=mid-1;
			}
			f2[l]=a[i];
 
		}
	} 
	cout<<len+1<<"\n"<<size;
	return 0;
}
